import { SlideButton } from '@/registry/ebonui/ui/slide-button';
import Link from 'next/link';

export function SlideButtonDemo() {
  return (
    <SlideButton
      asChild
      className="text-white"
      style={
        {
          '--liquid-button-color': '#3b82f6',
          '--liquid-button-background-color': '#020617',
        } as React.CSSProperties
      }
    >
      <Link href="/dashboard">Go to Dashboard</Link>
    </SlideButton>
  );
}
